/// <reference path="../typings/index.d.ts" />
import { BeSkill, Options, libraries } from '@be/be-framework';
import jibo = require('jibo');

import Analytics from './analytics/Analytics';
import HueControler from './HueControler';
import HueBridge from './api/hue/HueInterfaces';

import PromiseUtils = libraries.jibo_cai_utils.PromiseUtils;
import CancelTokenSession = libraries.jibo_cai_utils.CancelTokenSession;
import TimeUtils = libraries.jibo_cai_utils.TimeUtils;

const promisify = PromiseUtils.promisify;

const BRIDGE_SCAN_VALID_FOR_MILI: number = TimeUtils.minutesToMs(3);
const WAIT_TO_SETUP_MILI: number = TimeUtils.hoursToMs(8);

export default class HueControl extends BeSkill {

    private _kbm: jibo.kb.Model;
    private _root: jibo.kb.Node;
    private _blackboard: any;
    private _flow: jibo.flow.FlowExecutor;

    private _hueControler:HueControler;
    private _COLORCODES: any;
    private _analytics:Analytics;

    /**
     * HueControl skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
        this.exit = this.exit.bind(this);
        this._analytics = new Analytics(this);
    }

    // This runs between HJ do skill and skill opening.
    preload(done: (err?: any) => void): void {
        promisify((cb) => {
            jibo.loader.load('assets/colorcodes/ColorCodes.json', (err, result) => {
                this._COLORCODES = result;
                cb();
            })
        }).then(()=>this._kbm.loadRoot())
        .then((root) => {
            this._root = root;
        }).then(() => { done();
        }).catch((err) => {
            this.log.error('Error loading KB: ', err);
            done();
        });
    }

    //This runs when @be starts, as part of booting up
    postInit(done) {
        this._kbm = jibo.kb.createModel('/skills/hue-control');
        done();
    }

    /**
     * Start the skill
     * @method open
     */
    open(result: any, refresh: boolean, previousSkillName: string): void {
        //TODO: this is a hack to never disable listening at ORs
        jibo.mim.silentMenus = false;

        let intent:string;
        let group:string;
        let color:string;

        if (result && result.nlu) {
            if (result.nlu.intent){
                intent = result.nlu.intent;
            }
            if (result.nlu.entities.group){
                group = result.nlu.entities.group;
            }
            if (result.nlu.entities.color){
                color = result.nlu.entities.color;
            }
        }

        if (refresh){
            this.cleanup().then(()=>{this._startFlow(intent, true, group, color)});
        } else{
            this._startFlow(intent, false, group, color);
        }
    }

    private _startFlow(intent:string, refresh:boolean, group?:string, color?:string){
        this._hueControler = new HueControler(
            this.log.createChild('HueControler'),
            (this._root && this._root.data) ? this._root.data.hueBridges : [],
            (this._root && this._root.data) ? this._root.data.defaultGroupInfo : {},
            this._COLORCODES
        )

        this._blackboard = {
            launchIntent: intent,
            launchGroup: group,
            launchColor: color,
            refresh:refresh,
            skill: this,
            log: this.log,
            kbData: this._root ? this._root.data : null,
            hueControler: this._hueControler,
            bridgeScanValidForMili: BRIDGE_SCAN_VALID_FOR_MILI,
            waitToSetupMili: WAIT_TO_SETUP_MILI,
            analytics: this._analytics,
        };
        let options = {
            assetPack: this.assetPack,
            blackboard: this._blackboard
        };
        this._flow = jibo.flow.run(require('./flows/Main.flow'), options, (err, status) => {
            if (status === jibo.bt.Status.INTERRUPTED) { //If interupted dont call exit, cleaning up twice can cause problems.
                return;
            }
            this.exit();
        });
    }

    public cleanupViews(toEye?:boolean): Promise<void> {
        return new Promise((resolve) => {
            if (jibo.face.views.currentView && jibo.face.views.currentView.id !== 'eyeView') {
                jibo.face.views.changeView(
                    {
                        removeAll: true,
                        leaveEmpty: !toEye
                    },
                    () => {
                        resolve();
                    }, //onComplete
                    (err) => {
                        this.log.warn('Failed removing view', err);
                        resolve();
                    } //onFail
                );
            }
            else {
                jibo.face.views.forceEyeView(
                    () => {
                        resolve();
                    },
                    null, // onLoaded callback
                    null, // use default transitionOpen
                    null, // use default transitionClose
                    (err) => {
                        this.log.warn('Failed reseting view', err);
                        resolve();
                    }
                )
            }
        });
    }

    /**
     * Cleanup in-between skill refreshes
     * @method cleanup
     */
    cleanup(): Promise<[void]> {
        return Promise.all([
            this.cleanupViews(),
            this._hueControler.stopAndDestroy().then(()=>{this._hueControler = null}),
            this._flow.stopAndDestroy().then(()=>{this._flow = null;}),
        ]);
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done: () => void): void {
        this._close().then(done, (err) => {
            this.log.error('Error closing skill', err);
            done();
        });
    }

    private async _close(): Promise<void> {
        if (this._blackboard.lightsForget){
            this._root.data = {};
            this.log.info('Deleting all HUE kbData.');
        }else{
            this._root.data.hueBridges = this._hueControler.appAccounts;
            this.log.info('Set kbData.hueBridges to appAccounts: ', this._hueControler.appAccounts)

            this._root.data.defaultGroupInfo = this._hueControler.defaultGroupInfo;
            this.log.info('Set kbData.defaultGroupInfo to defaultGroupInfo: ', this._hueControler.defaultGroupInfo)
        }

        this._blackboard = null; //clean up skill's ref to blackboard.

        try {
            await this._flow.stopAndDestroy();
        } catch (err) {
            this.log.warn('Error cleaning up flow', err);
        }
        this._flow = null;

        try {
            await this._hueControler.stopAndDestroy();
        } catch (err) {
            this.log.warn('Error cleaning up hueControler', err);
        }

        try {
            await this.cleanupViews();
        } catch (err) {
            this.log.warn('Error cleaning up the views', err);
        }

        if (this._root) {
            try {
                await promisify(cb => this._root.save(cb));
            } catch (err) {
                this.log.warn('failed to save KB');
            }
            this._root = null;
        }
    }
}
